with WithAncestors AS (SELECT itemid FROM AncestorIds2 WHERE AncestorId in (100) ),WithItemLinkItemIds AS (select ItemLinks2.LinkedId From ItemLinks2 join withancestors on withancestors.itemid=itemlinks2.itemid  where ItemLinks2.Type=6 union select ItemLinks2TwoLevel.LinkedId from ItemLinks2 ItemLinks2TwoLevel where itemid in (select ItemLinks2.LinkedId From ItemLinks2 join withancestors on withancestors.itemid=itemlinks2.itemid  where ItemLinks2.Type in (7)))select A.Id,A.SortName from mediaitems A where (Exists (select 1 From ItemLinks2 join ancestorids2 on ancestorids2.itemid=itemlinks2.itemid and ancestorids2.ancestorid in (100)  where ItemLinks2.LinkedId = A.Id AND ItemLinks2.Type in (6)) OR Exists (select 1 from ItemLinks2 ItemLinks2TwoLevel where exists (select 1 From ItemLinks2 join ancestorids2 on ancestorids2.itemid=itemlinks2.itemid and ancestorids2.ancestorid in (100)  where itemlinks2.linkedid = itemlinks2twolevel.itemid AND ItemLinks2.Type in (7)) and ItemLinks2TwoLevel.LinkedId=A.Id)) ORDER BY A.SortName collate NATURALSORT ASC LIMIT 12
